## Recommended Improvements

Here's what a hardened version would look like:

```js
const express = require('express');
const helmet = require('helmet');        // Security headers
const rateLimit = require('express-rate-limit'); // Rate limiting

const app = express();
const PORT = process.env.PORT || 3000;

// --- Security Middleware ---

// Set secure HTTP headers (removes X-Powered-By, adds CSP, HSTS, etc.)
app.use(helmet());

// Parse JSON bodies with a size limit to prevent large-payload attacks
app.use(express.json({ limit: '10kb' }));

// Rate limiting — prevent brute-force / DoS
const limiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100,                  // limit each IP to 100 requests per window
  standardHeaders: true,
  legacyHeaders: false,
  message: { error: 'Too many requests, please try again later.' },
});
app.use(limiter);

// --- Routes ---

app.get('/health', (req, res) => {
  res.json({ status: 'ok', timestamp: new Date().toISOString() });
});

app.get('/users', (req, res) => {
  // In production, validate/sanitize any query params here, e.g.:
  //   const { page, limit } = validatePagination(req.query);
  res.json([
    { id: 1, name: 'Alice', email: 'alice@example.com' },
    { id: 2, name: 'Bob', email: 'bob@example.com' },
  ]);
});

// --- 404 Handler ---
app.use((req, res) => {
  res.status(404).json({ error: 'Not Found' });
});

// --- Global Error Handler ---
// Express requires all 4 parameters to recognize this as an error handler
app.use((err, req, res, next) => {
  console.error('Unhandled error:', err.message);
  // Never leak stack traces or internal details to the client
  res.status(err.status || 500).json({
    error: process.env.NODE_ENV === 'production'
      ? 'Internal Server Error'
      : err.message,
  });
});

// --- Graceful Startup & Shutdown ---
const server = app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
});

process.on('SIGTERM', () => {
  console.log('SIGTERM received. Shutting down gracefully...');
  server.close(() => {
    console.log('Server closed.');
    process.exit(0);
  });
});

module.exports = app;
```

